#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    long long subarrayProductBelowK(vector<int>& arr, int k) {
        if (k <= 1) {
            return 0;
        }
        long long product = 1;
        long long count = 0;
        int left = 0;

        for (int right = 0; right < (int)arr.size(); right++) {
            product *= arr[right];
            while (product >= k) {
                product /= arr[left];
                left++;
            }
            count += right - left + 1;
        }

        return count;
    }
};

import java.util.*;

class Solution {
    public static long subarrayProductBelowK(int[] arr, int k) {
        if (k <= 1) return 0;
        long product = 1;
        int left = 0;
        long count = 0;
        for (int right = 0; right < arr.length; right++) {
            product *= arr[right];
            while (product >= k) {
                product /= arr[left];
                left++;
            }
            count += right - left + 1;
        }
        return count;
    }
}

class solution:
    def subarrayProductBelowK(self, arr, k):
        if k <= 1:
            return 0

        product = 1
        count = 0
        left = 0

        for right in range(len(arr)):
            product *= arr[right]
            while product >= k:
                product /= arr[left]
                left += 1
            count += right - left + 1

        return count
